const _currentUserId=parseInt(document.body.dataset.userId || '0',10);let _changePwTargetId=null;let _changePwModal=null;async function loadUsersList(){const tbody=document.getElementById('admin-users-table');tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted py-3">Загрузка…</td></tr>';const res=await window.Common.csrfFetch('/api/admin/users');if(!res.ok){tbody.innerHTML='<tr><td colspan="4" class="text-danger text-center py-3">Ошибка загрузки</td></tr>';return;}const users=await res.json();const esc=window.Common.escapeHtml;tbody.innerHTML=users.map(u=>{const isSelf=u.id===_currentUserId;const isRoot=u.username==='root';const actions=isSelf ? '<span class="text-muted small">—</span>':`<div class="d-flex gap-1 flex-wrap">${!isRoot ? `<button class="btn btn-sm btn-outline-primary" onclick="changePasswordTrigger(${u.id},'${esc(u.username)}')">Пароль</button>`:''}<button class="btn btn-sm btn-outline-danger" onclick="deleteUserTrigger(${u.id},'${esc(u.username)}')">Удалить</button></div>`;return `<tr><td class="text-muted small">${u.id}</td><td><b>${esc(u.username)}</b></td><td><span class="badge ${u.is_admin ? 'bg-danger':'bg-secondary'}">${u.is_admin ? 'Админ':'Юзер'}</span></td><td>${actions}</td></tr>`;}).join('');}function deleteUserTrigger(userId,name){window.Common.askConfirmation(`Удалить аккаунт «${name}» навсегда?`,async()=>{const res=await window.Common.csrfFetch(`/api/admin/delete_user/${userId}`,{method:'DELETE'});const data=await res.json();window.Common.showToast(data.message,!res.ok);loadUsersList();});}function changePasswordTrigger(userId,name){_changePwTargetId=userId;document.getElementById('changePwUsername').textContent=name;document.getElementById('changePwNew').value='';document.getElementById('changePwConfirm').value='';if(!_changePwModal){_changePwModal=new bootstrap.Modal(document.getElementById('changePwModal'));}_changePwModal.show();}document.getElementById('changePwSubmitBtn').addEventListener('click',async()=>{const newPw=document.getElementById('changePwNew').value.trim();const confirm=document.getElementById('changePwConfirm').value.trim();if(!newPw || newPw.length<8){window.Common.showToast('Пароль должен содержать минимум 8 символов.',true);return;}if(newPw !==confirm){window.Common.showToast('Пароли не совпадают.',true);return;}const btn=document.getElementById('changePwSubmitBtn');btn.disabled=true;btn.textContent='Сохранение…';try{const res=await window.Common.csrfFetch(`/api/admin/change_password/${_changePwTargetId}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({new_password:newPw}),});const data=await res.json();if(res.ok){if(_changePwModal)_changePwModal.hide();window.Common.showToast(data.message);}else{window.Common.showToast(data.message,true);}}finally{btn.disabled=false;btn.textContent='Сохранить';}});document.getElementById('adminCreateUserForm').addEventListener('submit',async e=>{e.preventDefault();const btn=document.getElementById('createUserBtn');btn.disabled=true;btn.textContent='Создание…';try{const res=await window.Common.csrfFetch('/api/admin/add_user',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('newUsername').value,password:document.getElementById('newPassword').value,is_admin:document.getElementById('isAdminCheck').checked,})});const data=await res.json();if(res.ok){window.Common.showToast(data.message);e.target.reset();loadUsersList();}else{window.Common.showSystemMessage(data.message,true);}}finally{btn.disabled=false;btn.textContent='Создать';}});loadUsersList();